import { Injectable, inject, signal, DestroyRef } from '@angular/core';
import { formatCurrency } from '@angular/common';
import { of, tap, catchError } from 'rxjs';
import { ConfirmationService } from 'primeng/api';
import { TranslateService } from '@ngx-translate/core';

import { AppInstallationService } from './app-installation.service';
import { ClientDataService } from '../../clients/services/client-data.service';
import { ModalFormService } from '../../../shared/services/forms/modal-form.service';
import { ModalListFormComponent } from '../../../shared/components/forms/modal-list-form/modal-list-form.component';
import {
  createTextAreaField,
  createTextField,
  createNumberField,
} from '../../../shared/models/form-field.model';
import { AppDefinition, FeeModel, InstallationEstimate, IntegrationPoint } from '../models/app-store.models';
import { isNullOrUndefined } from '../../../shared/utils';
import { getFeeLabel } from '../utils/fee.utils';
import { AuthDataService } from '../../../core/services/auth-data.service';
import { ACTION_EXPANSION } from '../models/app-store-permissions.constants';

/**
 * Facade service that centralises install, uninstall, and toggle-enabled logic.
 * Consumers inject this service and bind to its state signals instead of
 * duplicating the orchestration in each component.
 */
@Injectable({ providedIn: 'root' })
export class AppInstallFacadeService {
  private readonly appInstallationService = inject(AppInstallationService);
  private readonly clientDataService = inject(ClientDataService);
  private readonly modalFormService = inject(ModalFormService);
  private readonly confirmationService = inject(ConfirmationService);
  private readonly authDataService = inject(AuthDataService);
  private readonly translateService = inject(TranslateService);

  // ── UI state ────────────────────────────────────────────────────────────────
  readonly isPerformingAction = signal(false);
  readonly error = signal<string | null>(null);
  readonly isTogglingEnabled = signal(false);
  readonly toggleEnabledError = signal<string | null>(null);

  // ── Estimate ─────────────────────────────────────────────────────────────────
  readonly estimateLoading = signal(false);
  readonly estimate = signal<InstallationEstimate | null>(null);
  readonly estimateError = signal<string | null>(null);

  loadEstimate(appId: string, ownerId: string): void {
    this.estimate.set(null);
    this.estimateError.set(null);
    this.estimateLoading.set(true);

    this.appInstallationService
      .getInstallationEstimate(appId, ownerId)
      .pipe(
        tap((result) => this.estimate.set(result)),
        catchError((err) => {
          console.error('Estimate fetch error:', err);
          this.estimateError.set(
            this.translateService.instant('ADMIN.APP_STORE.INSTALL.ERROR_ESTIMATE'),
          );
          return of(null);
        }),
      )
      .subscribe({ complete: () => this.estimateLoading.set(false) });
  }

  // ── Install ─────────────────────────────────────────────────────────────────

  /**
   * Install an app. Opens a config modal for external (appSidebar) apps;
   * performs a direct install for all others.
   */
  installApp(
    app: AppDefinition,
    destroyRef: DestroyRef,
    onSuccess?: () => void,
  ): void {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) return;

    const missingPermissions = this.getMissingPermissions(app.integrationPoints ?? []);
    if (missingPermissions.length > 0) {
      this.showPermissionBlockDialog(missingPermissions);
      return;
    }

    if (app.feeModel != null) {
      this.confirmFeeAndInstall(app, clientId, destroyRef, onSuccess);
      return;
    }

    const isExternalApp = app.integrationPoints?.some(
      (point) => point.screenId === 'appSidebar',
    );

    if (isExternalApp) {
      this.openInstallConfigModal(app, clientId, destroyRef, onSuccess);
    } else {
      this.performInstallation(app.id, clientId, {}, onSuccess);
    }
  }

  private confirmFeeAndInstall(
    app: AppDefinition,
    clientId: string,
    destroyRef: DestroyRef,
    onSuccess?: () => void,
  ): void {
    const label = getFeeLabel(app.feeModel, this.translateService);
    const estimate = this.estimate();
    let message = this.translateService.instant(
      'ADMIN.APP_STORE.INSTALL.FEE_MESSAGE',
      { label },
    );
    if (
      estimate != null &&
      estimate.estimatedCost != null &&
      estimate.activeDeviceCount != null &&
      app.feeModel?.type === 'perActiveDevice'
    ) {
      const total = formatCurrency(estimate.estimatedCost, 'en-ZA', 'R', 'ZAR');
      message += this.translateService.instant(
        'ADMIN.APP_STORE.INSTALL.FEE_ESTIMATE',
        { count: estimate.activeDeviceCount, total },
      );
    }
    this.confirmationService.confirm({
      header: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIRM_HEADER'),
      message,
      icon: 'pi pi-credit-card',
      acceptLabel: this.translateService.instant('ADMIN.APP_STORE.INSTALL.AGREE_INSTALL'),
      rejectLabel: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CANCEL'),
      accept: () => {
        const isExternal = app.integrationPoints?.some(
          (p) => p.screenId === 'appSidebar',
        );
        if (isExternal) {
          this.openInstallConfigModal(app, clientId, destroyRef, onSuccess);
        } else {
          this.performInstallation(app.id, clientId, {}, onSuccess);
        }
      },
    });
  }

  private openInstallConfigModal(
    app: AppDefinition,
    clientId: string,
    destroyRef: DestroyRef,
    onSuccess?: () => void,
  ): void {
    const dummyField = createTextAreaField('dummy', 'dummy', undefined);

    this.modalFormService
      .openListItemModal<Record<string, string | number>>({
        modalConfig: {
          modalComponent: ModalListFormComponent,
          modalTitle: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_TITLE'),
          subHeader: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_SUBHEADER'),
          modalFields: [
            createTextField(
              'icon',
              this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_ICON_LABEL'),
              'browser',
              {
                placeholder: 'browser',
                hint: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_ICON_HINT'),
              },
            ),
            createTextField(
              'section',
              this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_SECTION_LABEL'),
              'Apps',
              {
                placeholder: 'Apps',
                hint: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_SECTION_HINT'),
              },
            ),
            createNumberField(
              'order',
              this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_ORDER_LABEL'),
              0,
              {
                hint: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CONFIG_ORDER_HINT'),
              },
            ),
          ],
          onSubmit: (data, ref) => {
            this.error.set(null);
            this.isPerformingAction.set(true);

            const config = {
              appSidebar: {
                icon: data['icon'] as string,
                section: data['section'] as string,
                order: data['order'] as number,
              },
            };

            return new Promise((resolve) => {
              this.appInstallationService
                .installExternalApp(app.id, clientId, config)
                .pipe(
                  tap(async () => {
                    this.error.set(null);
                    try {
                      await this.clientDataService.setSelectedClientById(
                        clientId,
                      );
                    } catch (e) {
                      console.warn('Failed to refresh client data:', e);
                    }
                    this.isPerformingAction.set(false);
                    onSuccess?.();
                    ref.close();
                    resolve(true);
                  }),
                  catchError((err) => {
                    console.error('App installation error:', err);
                    this.error.set(
                      this.translateService.instant('ADMIN.APP_STORE.INSTALL.ERROR_INSTALL'),
                    );
                    this.isPerformingAction.set(false);
                    resolve(false);
                    return of(null);
                  }),
                )
                .subscribe();
            });
          },
        },
        itemData: { icon: 'browser', section: 'Apps', order: 0 },
        destroyRef,
        field: dummyField,
      })
      .subscribe();
  }

  private performInstallation(
    appId: string,
    clientId: string,
    configuration: Record<string, unknown>,
    onSuccess?: () => void,
  ): void {
    this.error.set(null);
    this.isPerformingAction.set(true);

    this.appInstallationService
      .installApp(appId, clientId, configuration)
      .pipe(
        tap((installation) => {
          this.error.set(null);
          if (installation.pendingFeeAcknowledgement) {
            this.appInstallationService
              .acknowledgeFee(installation.id, clientId)
              .subscribe();
          }
          onSuccess?.();
        }),
        catchError((err) => {
          console.error('App installation error:', err);
          this.error.set(
            this.translateService.instant('ADMIN.APP_STORE.INSTALL.ERROR_INSTALL'),
          );
          return of(null);
        }),
      )
      .subscribe({ complete: () => this.isPerformingAction.set(false) });
  }

  // ── Permission Validation ─────────────────────────────────────────────────────

  /** Expands raw stored legacyRights permissions into full action set. */
  private buildExpandedPermissionSet(): Set<string> {
    const expanded = new Set<string>();
    for (const perm of this.authDataService.userPermissions()) {
      const colonIdx = perm.indexOf(':');
      if (colonIdx === -1) continue;
      const resource = perm.substring(0, colonIdx);
      const rawAction = perm.substring(colonIdx + 1);
      const actions = ACTION_EXPANSION[rawAction] ?? [rawAction];
      for (const action of actions) expanded.add(`${resource}:${action}`);
    }
    return expanded;
  }

  /** Returns missing "entity:action" strings for the app's integration points. */
  private getMissingPermissions(integrationPoints: IntegrationPoint[]): string[] {
    if (this.authDataService.userPermissions().includes('system:all')) return [];
    const expanded = this.buildExpandedPermissionSet();
    const missing = new Set<string>();
    for (const ip of (integrationPoints ?? [])) {
      for (const perm of (ip.requiredPermissions ?? [])) {
        const colonIdx = perm.indexOf(':');
        if (colonIdx === -1) continue;
        const entity = perm.slice(0, colonIdx);
        const action = perm.slice(colonIdx + 1);
        const normalized = entity.toLowerCase().endsWith('s')
          ? entity.toLowerCase().slice(0, -1)
          : entity.toLowerCase();
        if (!expanded.has(`${normalized}:${action}`)) missing.add(`${normalized}:${action}`);
      }
    }
    return [...missing];
  }

  private showPermissionBlockDialog(missingPermissions: string[]): void {
    const list = missingPermissions.map(p => `<li><code>${p}</code></li>`).join('');
    const intro = this.translateService.instant('ADMIN.APP_STORE.INSTALL.PERMISSION_BLOCK_INTRO');
    const footer = this.translateService.instant('ADMIN.APP_STORE.INSTALL.PERMISSION_BLOCK_FOOTER');
    this.confirmationService.confirm({
      header: this.translateService.instant('ADMIN.APP_STORE.INSTALL.PERMISSION_BLOCK_HEADER'),
      message: `${intro}<ul class="mt-2">${list}</ul><p class="mt-2 text-sm">${footer}</p>`,
      icon: 'pi pi-lock',
      acceptLabel: this.translateService.instant('ADMIN.APP_STORE.INSTALL.OK'),
      rejectVisible: false,
      accept: () => {},
    });
  }

  // ── Uninstall ────────────────────────────────────────────────────────────────

  /**
   * Uninstall an app by installation ID.
   * Pass `isExternalApp: true` for appSidebar apps so the correct endpoint is used.
   */
  uninstallApp(
    installationId: string,
    isExternalApp = false,
    onSuccess?: () => void,
  ): void {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) return;

    this.error.set(null);
    this.isPerformingAction.set(true);

    const uninstall$ = isExternalApp
      ? this.appInstallationService.uninstallExternalApp(
          installationId,
          clientId,
        )
      : this.appInstallationService.uninstallApp(installationId, clientId);

    uninstall$
      .pipe(
        tap(async () => {
          this.error.set(null);
          if (isExternalApp) {
            try {
              await this.clientDataService.setSelectedClientById(clientId);
            } catch (e) {
              console.warn('Failed to refresh client data:', e);
            }
          }
          onSuccess?.();
        }),
        catchError((err) => {
          console.error('App uninstallation error:', err);
          this.error.set(
            this.translateService.instant('ADMIN.APP_STORE.INSTALL.ERROR_UNINSTALL'),
          );
          return of(null);
        }),
      )
      .subscribe({ complete: () => this.isPerformingAction.set(false) });
  }

  // ── Toggle enabled ───────────────────────────────────────────────────────────

  // ── Fee Acknowledgement ──────────────────────────────────────────────────────

  acknowledgeFeeForInstallation(
    installationId: string,
    feeModel: FeeModel | null,
    onSuccess?: () => void,
  ): void {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) return;

    const label = getFeeLabel(feeModel, this.translateService);
    this.confirmationService.confirm({
      header: this.translateService.instant('ADMIN.APP_STORE.INSTALL.FEE_CHANGED_HEADER'),
      message: this.translateService.instant(
        'ADMIN.APP_STORE.INSTALL.FEE_CHANGED_MESSAGE',
        { label },
      ),
      icon: 'pi pi-credit-card',
      acceptLabel: this.translateService.instant('ADMIN.APP_STORE.INSTALL.ACCEPT'),
      rejectLabel: this.translateService.instant('ADMIN.APP_STORE.INSTALL.CANCEL'),
      accept: () => {
        this.appInstallationService
          .acknowledgeFee(installationId, clientId)
          .pipe(
            tap(() => onSuccess?.()),
            catchError((err) => {
              console.error('Fee acknowledgement error:', err);
              return of(null);
            }),
          )
          .subscribe();
      },
    });
  }

  toggleEnabled(
    installationId: string,
    currentValue: boolean,
    onSuccess?: () => void,
  ): void {
    const clientId = this.clientDataService.getSelectedClient()?.id;
    if (isNullOrUndefined(clientId)) return;

    this.toggleEnabledError.set(null);
    this.isTogglingEnabled.set(true);

    this.appInstallationService
      .setEnabled(installationId, clientId, !currentValue)
      .pipe(
        tap(() => onSuccess?.()),
        catchError((err) => {
          console.error('Toggle enabled error:', err);
          this.toggleEnabledError.set(
            this.translateService.instant('ADMIN.APP_STORE.INSTALL.ERROR_TOGGLE'),
          );
          return of(null);
        }),
      )
      .subscribe({ complete: () => this.isTogglingEnabled.set(false) });
  }
}
